 9→        x={0}
10→        y={0}
11→        textAnchor="middle"
12→        dominantBaseline="middle"
13→        fill="var(--color-text-secondary)"
14→        fontSize={180}
15→        fontFamily="var(--font-blueprint)"
16→      >
17→        {message}
