23→function SectionDiagnosticMessage({ scene, message }) {
24→  if (!scene || !message) return null;
25→
26→  return (
27→    <text
28→      x={(scene.bounds.minX + scene.bounds.maxX) / 2}
29→      y={-scene.bounds.maxZ - 170}
30→      textAnchor="middle"
31→      dominantBaseline="middle"
32→      fill="var(--color-text-secondary)"
33→      fontSize={150}
34→      fontFamily="var(--font-blueprint)"
35→      style={{ pointerEvents: 'none' }}
36→    >
37→      {message}
38→    </text>
