42→export default function TrussSectionRenderer({ project, floor, activeSectionCutId }) {
43→  const cuts = floor?.sectionCuts || [];
44→  const sectionCut = (activeSectionCutId && cuts.find((entry) => entry.id === activeSectionCutId)) || cuts[0] || null;
45→
46→  if (!sectionCut || !floor) {
47→    return <EmptyState message="Add a section cut on the active floor to view trusses in section." />;
48→  }
49→
50→  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
51→  if (!scene) return null;
52→  const trussMessage = getSectionVisibilityMessage('truss', scene.diagnostics?.truss?.reason);
53→
54→  return (
55→    <g className="truss-section-view">
56→      <SectionSceneLayer scene={scene} />
57→      <SectionDiagnosticMessage scene={scene} message={trussMessage} />
58→    </g>
59→  );
60→}
