  1→import { DRAWING_GRAPHICS, SHEET_COLORS } from '@/sheets/standards';
  2→import { ANNOTATION_SEMANTIC_ROLES, ANNOTATION_TRUST_LEVELS } from '@/annotations/policy';
  3→
  4→function estimateTextWidth(text, fontSize) {
  5→  return Math.max(fontSize * 1.2, String(text || '').length * fontSize * 0.58);
  6→}
  7→
  8→function Arrowhead({ arrow }) {
  9→  return (
 10→    <polyline
 11→      points={`${arrow.left.x},${arrow.left.y} ${arrow.tip.x},${arrow.tip.y} ${arrow.right.x},${arrow.right.y}`}
 12→      fill="none"
 13→      stroke={DRAWING_GRAPHICS.annotation.dimensionStroke}
 14→      strokeWidth={DRAWING_GRAPHICS.annotation.dimensionStrokeWidth}
 15→      vectorEffect="non-scaling-stroke"
 16→    />
 17→  );
 18→}
 19→
 20→function DimensionTextMask({ figure, fontSize }) {
 21→  const width = estimateTextWidth(figure.text.value, fontSize) + DRAWING_GRAPHICS.annotation.textMaskPaddingX;
 22→  const height = fontSize + DRAWING_GRAPHICS.annotation.textMaskPaddingY;
 23→
 24→  return (
 25→    <rect
 26→      x={figure.text.position.x - width / 2}
 27→      y={figure.text.position.y - height / 2}
 28→      width={width}
 29→      height={height}
 30→      fill={SHEET_COLORS.mask}
 31→      opacity={0.92}
 32→      transform={`rotate(${figure.text.angle}, ${figure.text.position.x}, ${figure.text.position.y})`}
 33→    />
 34→  );
 35→}
 36→
 37→function DimensionFigure({ figure }) {
 38→  const fontSize = DRAWING_GRAPHICS.annotation.textSize;
 39→
 40→  return (
 41→    <g key={figure.id}>
 42→      {figure.extensionLines.map((line, index) => (
 43→        <line
 44→          key={`${figure.id}-ext-${index}`}
 45→          x1={line.start.x}
 46→          y1={line.start.y}
 47→          x2={line.end.x}
 48→          y2={line.end.y}
 49→          stroke={DRAWING_GRAPHICS.annotation.dimensionExtension}
 50→          strokeWidth={DRAWING_GRAPHICS.annotation.dimensionExtensionWidth}
 51→          vectorEffect="non-scaling-stroke"
 52→        />
 53→      ))}
 54→      <line
 55→        x1={figure.lineStart.x}
 56→        y1={figure.lineStart.y}
 57→        x2={figure.lineEnd.x}
 58→        y2={figure.lineEnd.y}
 59→        stroke={DRAWING_GRAPHICS.annotation.dimensionStroke}
 60→        strokeWidth={DRAWING_GRAPHICS.annotation.dimensionStrokeWidth}
 61→        vectorEffect="non-scaling-stroke"
 62→      />
 63→      {figure.arrowheads.map((arrow, index) => (
 64→        <Arrowhead key={`${figure.id}-arrow-${index}`} arrow={arrow} />
 65→      ))}
 66→      <DimensionTextMask figure={figure} fontSize={fontSize} />
 67→      <text
 68→        x={figure.text.position.x}
 69→        y={figure.text.position.y}
 70→        textAnchor="middle"
 71→        dominantBaseline="middle"
 72→        fill={DRAWING_GRAPHICS.annotation.text}
 73→        fontSize={fontSize}
 74→        fontFamily="var(--font-blueprint)"
 75→        transform={`rotate(${figure.text.angle}, ${figure.text.position.x}, ${figure.text.position.y})`}
 76→        style={{ pointerEvents: 'none' }}
 77→      >
 78→        {figure.text.value}
 79→      </text>
 80→    </g>
 81→  );
 82→}
 83→
 84→function TagTextMask({ tag, fontSize, lineHeight, opacity = 0.92 }) {
 85→  const maxLineLength = Math.max(...tag.textLines.map((line) => String(line || '').length), 1);
 86→  const width = estimateTextWidth('X'.repeat(maxLineLength), fontSize) + (tag.maskPaddingX ?? 44);
 87→  const height = Math.max(lineHeight, tag.textLines.length * lineHeight) + (tag.maskPaddingY ?? 22);
 88→  const x = tag.textAnchor === 'start'
 89→    ? tag.position.x
 90→    : (tag.textAnchor === 'end' ? tag.position.x - width : tag.position.x - (width / 2));
 91→
 92→  return (
 93→    <rect
 94→      x={x}
 95→      y={tag.position.y - height / 2}
 96→      width={width}
 97→      height={height}
 98→      fill={SHEET_COLORS.mask}
 99→      opacity={opacity}
100→      transform={`rotate(${tag.angle || 0}, ${tag.position.x}, ${tag.position.y})`}
101→    />
102→  );
103→}
104→
105→function resolveTagStyle(tag, isRoom) {
106→  const isInformationalMeasurement = (
107→    tag.semanticRole === ANNOTATION_SEMANTIC_ROLES.MEASUREMENT
108→    && tag.trustLevel !== ANNOTATION_TRUST_LEVELS.AUTHORITATIVE
109→  );
110→
111→  if (isRoom) {
112→    return {
113→      textFill: DRAWING_GRAPHICS.annotation.text,
114→      fontWeight: 600,
115→      maskOpacity: 0.92,
116→      leaderStroke: DRAWING_GRAPHICS.annotation.dimensionExtension,
117→      leaderDash: undefined,
118→    };
119→  }
120→
121→  if (isInformationalMeasurement) {
122→    return {
123→      textFill: SHEET_COLORS.textMuted,
124→      fontWeight: 500,
125→      maskOpacity: 0.84,
126→      leaderStroke: SHEET_COLORS.borderMuted,
127→      leaderDash: '6 4',
128→    };
129→  }
130→
131→  return {
132→    textFill: DRAWING_GRAPHICS.annotation.textMuted,
133→    fontWeight: 500,
134→    maskOpacity: 0.92,
135→    leaderStroke: DRAWING_GRAPHICS.annotation.dimensionExtension,
136→    leaderDash: undefined,
137→  };
138→}
139→
140→function TagFigure({ tag }) {
141→  const isRoom = tag.sourceType === 'room';
142→  const nameSize = isRoom
143→    ? DRAWING_GRAPHICS.annotation.roomNameSize
144→    : (tag.fontSize ?? DRAWING_GRAPHICS.annotation.textSize);
145→  const areaSize = DRAWING_GRAPHICS.annotation.roomAreaSize;
146→  const lineHeight = isRoom ? 168 : (tag.lineHeight ?? 150);
147→  const startY = tag.position.y - ((tag.textLines.length - 1) * lineHeight) / 2;
148→  const style = resolveTagStyle(tag, isRoom);
149→
150→  return (
151→    <g key={tag.id}>
152→      {tag.leaderLine ? (
153→        <line
154→          x1={tag.leaderLine.start.x}
155→          y1={tag.leaderLine.start.y}
156→          x2={tag.leaderLine.end.x}
157→          y2={tag.leaderLine.end.y}
158→          stroke={style.leaderStroke}
159→          strokeWidth={DRAWING_GRAPHICS.annotation.dimensionExtensionWidth}
160→          strokeDasharray={style.leaderDash}
161→          vectorEffect="non-scaling-stroke"
162→        />
163→      ) : null}
164→      {tag.mask ? (
165→        <TagTextMask tag={tag} fontSize={nameSize} lineHeight={lineHeight} opacity={style.maskOpacity} />
166→      ) : null}
167→      <text
168→        x={tag.position.x}
169→        y={startY}
170→        textAnchor={tag.textAnchor}
171→        dominantBaseline="middle"
172→        fill={style.textFill}
173→        fontSize={nameSize}
174→        fontWeight={style.fontWeight}
175→        fontFamily="var(--font-blueprint)"
176→        transform={`rotate(${tag.angle || 0}, ${tag.position.x}, ${tag.position.y})`}
177→        style={{ pointerEvents: 'none' }}
178→      >
179→        {tag.textLines.map((line, index) => (
180→          <tspan
181→            key={`${tag.id}-line-${index}`}
182→            x={tag.position.x}
183→            dy={index === 0 ? 0 : lineHeight}
184→            fontSize={isRoom && index > 0 ? areaSize : nameSize}
185→            fill={isRoom && index > 0 ? DRAWING_GRAPHICS.annotation.textMuted : undefined}
186→            fontWeight={isRoom && index > 0 ? 500 : undefined}
187→          >
188→            {line}
189→          </tspan>
190→        ))}
191→      </text>
192→    </g>
193→  );
194→}
195→
196→export default function BlueprintAnnotationLayer({ dimensions = [], tags = [], className = 'annotations' }) {
197→  return (
198→    <g className={className}>
199→      {dimensions.map((figure) => (
200→        <DimensionFigure key={figure.id} figure={figure} />
201→      ))}
202→      {tags.map((tag) => (
203→        <TagFigure key={tag.id} tag={tag} />
204→      ))}
205→    </g>
206→  );
207→}
