 42→function normalizeMaterial(material = 'timber') {
 43→  return material === 'metal' ? 'metal' : 'timber';
 44→}
 45→
 46→function getTrussMemberMaterialKey(memberType, material = 'timber') {
 47→  const normalizedMaterial = normalizeMaterial(material);
 48→  if (memberType === 'web') return `trussWeb_${normalizedMaterial}`;
 49→  return `trussChord_${normalizedMaterial}`;
 50→}
 51→
 52→function getPurlinMaterialKey(material = 'timber') {
 53→  return `trussPurlin_${normalizeMaterial(material)}`;
 54→}
 55→
 56→function createBounds(points = []) {
 57→  if (!points.length) {
 58→    return {
 59→      minX: 0,
 60→      maxX: 1000,
 61→      minY: 0,
 62→      maxY: 1000,
 63→      minElevation: 0,
 64→      maxElevation: 1000,
 65→    };
