46→export function roundMeasurementValue(mm, projectOrPolicy = null, options = {}) {
47→  const policy = resolveMeasurementPolicy(projectOrPolicy, options.policy);
48→  const absolute = options.absolute ?? true;
49→  const rawValue = Number(mm) || 0;
