54→export function formatMeasurementValue(mm, projectOrPolicy = null, options = {}) {
55→  const policy = resolveMeasurementPolicy(projectOrPolicy, options.policy);
56→  const roundedValue = roundMeasurementValue(mm, policy, options);
57→  const valueText = policy.lengthPrecision > 0
58→    ? roundedValue.toFixed(policy.lengthPrecision)
59→    : String(Math.round(roundedValue));
60→
61→  return `${valueText} ${policy.lengthUnit}`;
